class Solution:
    def sortJumbled(self, mapping, nums):
        """
        :type mapping: List[int]
        :type nums: List[int]
        :rtype: List[int]
        """
        def getMappedValue(num):
            result = 0
            multiplier = 1
            digits = []

            if num == 0:
                digits = [0]
            else:
                while num > 0:
                    digits.append(num % 10)
                    num //= 10

            digits.reverse()
            for digit in digits:
                result = result * 10 + mapping[digit]

            return result

        return sorted(nums, key=getMappedValue)
